import{_ as i,o as a,c as o,ag as l}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Aliasuri Dig | Dotfiles (RO)","titleTemplate":":title","description":"Comenzi scurte pentru interogări DNS. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","frontmatter":{"title":"Aliasuri Dig | Dotfiles","description":"Comenzi scurte pentru interogări DNS. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","lang":"ro-RO","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasuri Dig | Previzualizare Dotfiles","canonical":"/ro/aliases/dig/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasuri Dig","pageType":"docs","schemaType":"WebPage","permalink":"/ro/aliases/dig/"},"headers":[],"relativePath":"ro/aliases/dig/index.md","filePath":"ro/aliases/dig/index.md","lastUpdated":1773010926000}'),r={name:"ro/aliases/dig/index.md"};function t(d,e,n,s,c,u){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="aliasuri-dig" tabindex="-1">Aliasuri Dig <a class="header-anchor" href="#aliasuri-dig" aria-label="Permalink to &quot;Aliasuri Dig&quot;">​</a></h1><p>Comenzi scurte pentru interogări DNS.</p><p>Această pagină prezintă un grup de aliasuri și scurtăturile sale de comandă obișnuite. Citiți-o mai întâi pentru a înțelege convențiile de denumire, intrările așteptate și tiparele de execuție sigure. Apoi deschideți anexa de referință pentru inventarul complet de comenzi și sintaxa exactă. Aceste aliasuri reduc tastarea repetitivă și mențin un comportament consistent pe macOS, Linux și WSL.</p><h2 id="cand-se-utilizeaza" tabindex="-1">Când se utilizează <a class="header-anchor" href="#cand-se-utilizeaza" aria-label="Permalink to &quot;Când se utilizează&quot;">​</a></h2><p>Utilizați această pagină înainte de lucrul zilnic în shell când aveți nevoie de tipare de comandă previzibile.</p><h2 id="ce-este-inclus" tabindex="-1">Ce este inclus <a class="header-anchor" href="#ce-este-inclus" aria-label="Permalink to &quot;Ce este inclus&quot;">​</a></h2><ul><li>Aliasuri: 10</li><li>Funcții helper: 0</li><li>Fișiere sursă: 1</li></ul><h2 id="exemple-rapide" tabindex="-1">Exemple rapide <a class="header-anchor" href="#exemple-rapide" aria-label="Permalink to &quot;Exemple rapide&quot;">​</a></h2><ul><li><code>d</code> → <code>dig</code></li><li><code>d4</code> → <code>dig +short -4</code></li><li><code>d6</code> → <code>dig +short -6</code></li><li><code>dga</code> → <code>dig +all ANY</code></li><li><code>dgs</code> → <code>dig +short</code></li><li><code>digg</code> → <code>dig @8.8.8.8 +nocmd any +multiline +noall +answer</code></li><li><code>ip4</code> → <code>dig +short myip.opendns.com @resolver1.opendns.com -4</code></li><li><code>ip6</code> → <code>dig -6 AAAA +short myip.opendns.com. @resolver1.opendns.com.</code></li><li><code>ips</code> → <code>ip4; ip6</code></li><li><code>wip</code> → <code>dig +short myip.opendns.com @resolver1.opendns.com</code></li></ul><h2 id="pasul-urmator" tabindex="-1">Pasul următor <a class="header-anchor" href="#pasul-urmator" aria-label="Permalink to &quot;Pasul următor&quot;">​</a></h2><p>Deschideți lista completă:</p>',11)])])}const g=i(r,[["render",t]]);export{m as __pageData,g as default};
